void runPipeline() throws Exception {
    java.util.concurrent.BlockingQueue<Integer> q = new java.util.concurrent.ArrayBlockingQueue<>(2);

    Thread producer = new Thread(() -> {
        try {
            for (int i = 1; i <= 5; i++) {
                q.put(i);
            }
            q.put(-1); // poison pill
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    });

    Thread consumer = new Thread(() -> {
        try {
            while (true) {
                int v = q.take();
                if (v == -1) break;
                System.out.println("consume=" + v);
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    });

    producer.start();
    consumer.start();
    producer.join();
    consumer.join();
}
